      expect(response.code.to_i).to eq(200)
      _body = response.body && !response.body.empty? ? JSON.parse(response.body) : nil
      expect(_body).to eq({ 'test' => { 'content' => '<file content>', 'content_type' => 'text/plain', 'filename' => 'test.txt', 'size' => 14 } })
    end
  end
end
